def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        if ratio == 1:
            score = 0.0
        elif ratio > 0.9:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.7 < ratio <= 0.9:
            score = np.exp(-((ratio - 0.7) * 20)) + 0.2
        elif 0.4 < ratio <= 0.7:
            score = 1.5 * np.log1p(1 - ratio) + 0.1
        elif ratio <= 0.4:
            score = 0.0
            power_sum = 0.0
            for k in range(1, 8):
                term = ((-1) ** (k+1)) * (ratio ** k) / (k * 2.0)
                power_sum += term
                if power_sum < 0:
                    power_sum = abs(power_sum) * 0.5
            score = power_sum + 0.05
        else:
            score = 1.0
        neighbors_influence = 0.0
        max_neighbors = min(6, n)
        for offset in range(1, max_neighbors):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            local_influence = 0.0
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    local_influence += diff_ratio * weight * 0.1
            neighbors_influence += local_influence
        capacity_factor = np.sqrt(capacity) + (item * 0.1)
        if capacity_factor == 0:
            capacity_factor = 1
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        elif priority > 1.5:
            priority = 1.5
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    median_finite = np.median(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            replacement = median_finite * np.random.uniform(3,6)
            priorities[i] = replacement
    for _ in range(2):
        for i in range(n):
            val = priorities[i]
            if val < 0.1:
                priorities[i] = val + 0.05
            elif val > 1.0:
                priorities[i] = val - 0.1
            neighbors = []
            if i > 0:
                neighbors.append(i-1)
            if i < n-1:
                neighbors.append(i+1)
            for ni in neighbors:
                diff = priorities[ni] - val
                adjustment = diff * 0.1
                priorities[i] += adjustment * 0.5
                priorities[ni] -= adjustment * 0.5
    return priorities
